  ('pukao-7fec267e-moex-00674', 'pukao-7fec267e', 'pukao-7fec267e-moex-110-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '行政機關對現行違反行政法上義務之行為人確認其身分。如行為人拒絕身分查證，且不願隨同到指定處 所接受身分查證者，行政機關得會同警察人員強制為之。警察機關何時應拒絕會同行政機關執行前述強 制行為？', '["有經費不足等事由，即應拒絕", "身分查證屬警察機關之職務，故不得拒絕", "無法即時確認行為人是否違反義務，即應拒絕", "會同辦理，將嚴重妨害警察機關自身職務之執行，即應拒絕"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:17+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00675', 'pukao-7fec267e', 'pukao-7fec267e-moex-110-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '關於行政機關管轄權之敘述，下列何者錯誤？', '["行政機關之管轄權，原則上應依據組織法規或其他行政法規定之", "基於管轄權恆定原則，無論何種情形下管轄權皆不可能發生變動", "數機關就同一事件依法皆有管轄權者，依受理先後順序判定", "關於管轄權之有無，行政機關應依職權調查"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:17+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00676', 'pukao-7fec267e', 'pukao-7fec267e-moex-110-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '下列何者非屬行政程序法第12條規定，得作為判定管轄權之審酌依據？', '["不動產之所在地", "自然人之住所或居所", "經營企業之處所", "行政法院所在地"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:17+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00677', 'pukao-7fec267e', 'pukao-7fec267e-moex-110-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '依公務員懲戒法之規定，關於懲戒處分，下列敘述何者正確？', '["申誡處分，得以口頭或書面為之", "受降級處分者，依現職之俸（薪）級降一級至三級改敘", "罰款之懲戒處分得與剝奪、減少退休（職、伍）金之懲戒處分併為處分", "剝奪、減少退休（職、伍）金之懲戒處分，以退休（職、伍）或其他原因離職之公務員為限"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:17+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00678', 'pukao-7fec267e', 'pukao-7fec267e-moex-110-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '依公務人員考績法之規定，關於公務人員考績之敘述，下列何者錯誤？', '["年終考績應以平時考核為依據，就受考人之工作、操行、學識、才能行之", "平時考核之獎勵分嘉獎、記功、記大功；懲處分申誡、記過、記大過", "平時考核之獎懲得互相抵銷，無獎懲抵銷而累積達二大過者，年終考績應列丙等", "任本職等年終考績已2年列甲等者，取得同官等高一職等之任用資格"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:17+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00679', 'pukao-7fec267e', 'pukao-7fec267e-moex-110-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '依公務員服務法之規定，下列敘述何者錯誤？', '["公務員服務法對於其他公營事業機關之服務人員，亦有適用", "公務員於其離職後3年內，不得擔任與其離職前5年內之職務直接相關之營利事業董事", "機關首長兼任教學或研究工作者，應經上級主管機關許可", "公務員不得投資非屬其服務機關監督之農、工、礦、交通或新聞出版事業"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:17+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00680', 'pukao-7fec267e', 'pukao-7fec267e-moex-110-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '依最高行政法院實務見解，關於公務人員權利救濟之敘述，下列何者正確？', '["公務人員如單就年終考績評定不服而循序提起行政訴訟時，原則上應以銓敘部為被告", "公務人員對於經考列丙等之年終考績，如有不服，得於申訴、再申訴後，提起行政訴訟以資救濟", "任主管人員之公務人員不服將其調任為非主管人員時，因已喪失主管加給，得循序提起行政訴訟以資 救濟", "公務人員如就考績獎懲結果之銓敘審定不服而循序提起行政訴訟時，原則上應以銓敘部為被告"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:17+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL),
  ('pukao-7fec267e-moex-00681', 'pukao-7fec267e', 'pukao-7fec267e-moex-110-d1a761c9', 'sub-pukao-7fec267e-03', NULL, 'single_choice', '下列何種人員非得準用公務人員保障法之規定？', '["行政機關進用之臨時人員", "公營事業依法任用之人員", "各機關依法僱用或留用人員", "私立學校改制為公立學校未具任用資格之留用人員"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:36:17+00:00", "source_pdf_sha1": "a73ca5f9bf9d", "answer_pdf_sha1": "702dcf1a18a2", "source_family": "moex-gov-tw", "moex": {"exam_code": "110090", "c": "401", "s": "0606", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "110", "exam_name": "110年公務人員高等考試三級考試暨普通考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "civil_slug": "pukao", "civil_category": "一般行政"}'::jsonb, NULL)
